const payload = $input.first().json;
const amountFormatted = (payload.amount_cents / 100).toFixed(2);

return [{
  json: {
    subject: `Payout approved — Q${amountFormatted} via ${payload.method}`,
    body: `A withdrawal request has been approved.\n\nUser ID: ${payload.user_id}\nAmount: Q${amountFormatted} GTQ\nMethod: ${payload.method}\nApproved by Admin ID: ${payload.admin_id}\nTrace ID: ${payload.trace_id || 'n/a'}\n\nProceed with the transfer through the ${payload.method} payment channel.`,
    user_id: payload.user_id,
    amount_cents: payload.amount_cents,
    method: payload.method,
    admin_id: payload.admin_id,
    trace_id: payload.trace_id
  }
}];
